mapper.select:
SELECT card_news_oid AS cardNewsOid, card_news_nm AS cardNewsNm, inq_cnt AS inqCnt, CASE WHEN open_yn = 'Y' THEN '공개' WHEN open_yn = 'N' THEN '미공개' ELSE '' END AS openState, DATE_FORMAT(reg_dt, '%Y-%m-%d') AS regDt FROM ${schema}.card_news
use_yn = 'Y'
AND ( card_news_oid LIKE CONCAT('%', #{keyword}, '%') OR card_news_nm LIKE CONCAT('%', #{keyword}, '%') )
AND open_yn = #{openYn}
AND DATE_FORMAT(reg_dt, '%Y-%m-%d') >= #{startDt} AND DATE_FORMAT(reg_dt, '%Y-%m-%d') <= #{endDt}
ORDER BY card_news_oid DESC

mapper.update:
UPDATE ${schema}.card_news
SET inq_cnt = inq_cnt + 1
WHERE card_news_oid = #{cardNewsOid}
